{
  "schemaVersion": 3,
  "judgeId": "judge_1",
  "batchIndex": 3,
  "comparisons": [
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_01",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 bám sát yêu cầu 'tự đi biển' với cơ chế khai thác vật lý rõ ràng, tính toán thủy triều và giới hạn thể lực thực tế. dt_01_concept_01 thiên về nấu ăn, thiếu tính đột phá về nghề biển và đối thủ khá rập khuôn."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_02",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 thể hiện hành động chủ động khai thác hải sản với rủi ro thực tế (sóng, hụt chân), tạo agency mạnh. dt_01_concept_02 dùng background 'kỹ sư công nghệ sinh học' hơi hiện đại và khiên cưỡng cho bối cảnh làng biển thập niên 80."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_03",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 có vòng lặp khai thác - bán - nâng cấp công cụ rất khớp với yêu cầu phát triển 30 chương. dt_01_concept_03 thụ động hơn khi phải chờ người mang lưới đến sửa, thiếu tính 'tự đi biển' và chủ động tìm kiếm nguồn lợi."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_04",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 khai thác nhum/ốc đá mang lại giá trị kinh tế thuyết phục và rủi ro cao, tạo áp lực tốt. dt_01_concept_04 dùng rong biển làm thức ăn chính hơi thiếu thuyết phục về mặt thị hiếu thập niên 80, background 'nhà sinh học biển' hơi học thuật."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_05",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 tập trung vào cốt lõi 'tự đi biển' và 'nhận ra phần sản lượng bị đánh giá thấp' (nhum biển). dt_01_concept_05 làm hầm đá rất hay nhưng thiên về dịch vụ hậu cần, c4 mang lại cảm giác phiêu lưu và thu hoạch trực tiếp tốt hơn."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_06",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 có cơ chế đánh bắt bằng tay không và nâng cấp dần lên tổ lặn, rất sát với yêu cầu mở rộng quy mô nhóm nhỏ. dt_01_concept_06 sửa thuyền cũ tốn nhiều thời gian, khó tạo ra 'thành quả sớm' trong 3 chương đầu."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_07",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 giữ được chất mộc mạc, bươn chải của dân biển. dt_01_concept_07 đưa 'chuyên gia marketing' vào bối cảnh bao cấp là vi phạm ranh giới về tư duy hiện đại vượt điều kiện thời đại."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_08",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 dùng trí nhớ không gian 3D để tính toán thủy triều, vẫn chịu rủi ro thời tiết và sức người. dt_01_concept_08 vi phạm ranh giới 'không biến ký ức tương lai thành tọa độ chính xác' khi đi tìm bãi sò mới."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_09",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 có hành động mạo hiểm, thu hoạch hải sản giá trị cao tạo cảm giác khoái hoạt mạnh và giải quyết nợ nần nhanh. dt_01_concept_09 chỉ phân loại muối, vòng lặp khá đơn điệu và khó kéo dài hấp dẫn trong 30 chương."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_10",
      "winnerId": "c4_rock_pool_tides",
      "reason": "c4 hoàn toàn phù hợp bối cảnh kinh tế khai thác. dt_01_concept_10 đưa khái niệm 'du lịch sinh thái' vào thập niên 80 là cực kỳ sai lệch về mặt lịch sử và vi phạm ranh giới bối cảnh."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c6_handline_bait",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 giải quyết bài toán 'thành quả sớm' cực tốt bằng mắm xổi ngắn ngày, phù hợp kinh tế hộ gia đình. c6 câu cá mú bán cho tàu Hong Kong hơi xa rời thực tế giao thương ven bờ quy mô nhỏ thập niên 80."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 có vòng lặp tái đầu tư từ mắm xổi sang mắm dài hạn rất vững chắc và sát với văn hóa ẩm thực cốt lõi. c7 vận chuyển bề bề sống bằng sức người đạp xe 20km liên tục vừa bơm khí hơi phi lý về mặt giới hạn thể lực."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 tận dụng phế phẩm (moi nát) để tạo dòng tiền nhanh, đúng tinh thần 'nhận ra phần sản lượng bị đánh giá thấp'. c5 cũng thể hiện tính 'gia đình ấm lên từng bước' qua các bữa cơm chan mắm rõ nét và đời thường hơn."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 có vòng quay vốn 10 ngày, đáp ứng hoàn hảo yêu cầu 'thành quả sớm'. c9 cắm cọc nuôi hàu phải chờ nhiều tháng, dù có bắt cá đối bù đắp nhưng nhịp độ cốt truyện chính bị kéo giãn, vi phạm yêu cầu không kéo dài sự bất lực."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c10_net_modifications",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 cho MC quyền chủ động hoàn toàn từ thu mua đến chế biến và bán lẻ. c10 phụ thuộc vào việc chủ tàu có dám thử lưới độ hay không, làm giảm agency của MC trong giai đoạn đầu."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_01",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 có cơ chế kiểm soát nhiệt độ và thính gạo rất chi tiết, mang tính kỹ thuật nghề nghiệp rõ nét. dt_01_concept_01 chỉ đơn thuần là xào nấu trứng cá, thiếu chiều sâu cơ chế và dễ lặp lại."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_02",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 chọn ngách 'mắm xổi' để có dòng tiền nhanh, thể hiện sự thông minh thực tế và bám sát yêu cầu thành quả sớm. dt_01_concept_02 dùng 'kỹ sư công nghệ sinh học' để cứu mắm hỏng, hơi nặng tính học thuật và thiếu sự mộc mạc."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_03",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 tạo ra sản phẩm tiêu dùng trực tiếp, dễ dàng mở rộng quy mô từ chợ lẻ lên hợp tác xã. dt_01_concept_03 sửa lưới mang tính dịch vụ nhỏ lẻ, khó bứt phá thành một cơ nghiệp lớn có tính thị trường hóa trong 30 chương."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_04",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 khai thác con moi làm mắm là một nghề truyền thống có thật và có giá trị kinh tế rõ ràng. dt_01_concept_04 hái rong biển làm thức ăn chính không phản ánh đúng trọng tâm kinh tế biển và khẩu vị thập niên 80."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_05",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 có chuỗi giá trị hoàn chỉnh từ nguyên liệu đến bàn ăn, dễ dàng tạo mâu thuẫn thương mại. dt_01_concept_05 làm hầm đá giữ lạnh là một ý tưởng phụ trợ tốt, nhưng để làm trục chính cho 30 chương thì c5 có nhiều không gian phát triển hơn."
    }
  ]
}
